import { describe, expect, it } from 'vitest';
import {
  initAttestationChain,
  attestHop,
  type AttestationSigner,
  type AttestationVerifier,
  type ChainBuildContext,
  type PrismAttestationChain,
} from './prism-attestation';
import {
  issueHumanAttestation,
  verifyHumanAttestation,
  canonicalHumanAttestationBytes,
  canonicalDetectionResultBytes,
  hashDetectionResult,
  detectionResultMatchesCertificate,
  DEFAULT_CALIBRATION_BOUND,
  type HumanDetectionResult,
  type HumanAttestationCertificate,
} from './human-attestation-certificate';
import type { PrismPath } from './temporal-prism';

// ─── Mock Crypto (same pattern as slowness-certificate.test.ts) ────

function mockSigner(did: string): AttestationSigner {
  return {
    did,
    async sign(message: Uint8Array): Promise<Uint8Array> {
      const sigText = `sig(${did})|${Array.from(message).join(',')}`;
      return new TextEncoder().encode(sigText);
    },
  };
}

const mockVerifier: AttestationVerifier = {
  async verify(did: string, message: Uint8Array, signature: Uint8Array): Promise<boolean> {
    const expected = `sig(${did})|${Array.from(message).join(',')}`;
    const expectedBytes = new TextEncoder().encode(expected);
    if (signature.length !== expectedBytes.length) return false;
    for (let i = 0; i < signature.length; i++) {
      if (signature[i] !== expectedBytes[i]) return false;
    }
    return true;
  },
};

function mockHashFn(data: Uint8Array | string): string {
  const bytes = typeof data === 'string' ? new TextEncoder().encode(data) : data;
  let h = 0;
  for (let i = 0; i < bytes.length; i++) {
    h = (h * 31 + bytes[i]) >>> 0;
  }
  return h.toString(16).padStart(8, '0');
}

const ctx: ChainBuildContext = {
  hashFn: mockHashFn,
  verifier: mockVerifier,
};

// ─── Fixtures ───────────────────────────────────────────────────────

const mockPath: PrismPath = {
  source: 'GnosisTemporalPrism',
  originPidId: 'pid:sensor',
  targetPidId: 'pid:issuer',
  startEpochMs: 1_000_000,
  deliverAtEpochMs: 1_000_500,
  hops: [
    {
      fromPidId: 'pid:sensor', toPidId: 'pid:entropy-witness',
      fromLabel: 'Sensor', toLabel: 'EntropyWitness',
      propagationDelayMs: 100,
      departureEpochMs: 1_000_000, arrivalEpochMs: 1_000_100,
      arrivalPhase: 'rising', phaseScore: 0.9,
    },
    {
      fromPidId: 'pid:entropy-witness', toPidId: 'pid:metacog-witness',
      fromLabel: 'EntropyWitness', toLabel: 'MetacogWitness',
      propagationDelayMs: 100,
      departureEpochMs: 1_000_100, arrivalEpochMs: 1_000_200,
      arrivalPhase: 'rising', phaseScore: 0.85,
    },
    {
      fromPidId: 'pid:metacog-witness', toPidId: 'pid:cadence-witness',
      fromLabel: 'MetacogWitness', toLabel: 'CadenceWitness',
      propagationDelayMs: 100,
      departureEpochMs: 1_000_200, arrivalEpochMs: 1_000_300,
      arrivalPhase: 'peak', phaseScore: 0.8,
    },
    {
      fromPidId: 'pid:cadence-witness', toPidId: 'pid:issuer',
      fromLabel: 'CadenceWitness', toLabel: 'Issuer',
      propagationDelayMs: 200,
      departureEpochMs: 1_000_300, arrivalEpochMs: 1_000_500,
      arrivalPhase: 'peak', phaseScore: 0.75,
    },
  ],
  totalDelayMs: 500,
  actualArrivalEpochMs: 1_000_500,
  deliveryErrorMs: 0,
  averagePhaseScore: 0.825,
  onTime: true,
};

/** Build a valid multi-signal chain with 3 hops (entropy, metacog, cadence witnesses). */
async function buildMultiSignalChain(): Promise<PrismAttestationChain> {
  let chain = initAttestationChain({
    chainId: 'c-human-1',
    originDid: 'did:key:sensor',
    targetDid: 'did:key:issuer',
    path: mockPath,
    initialPayloadHash: 'h0',
    createdAtPLo: 1000,
  });
  chain = await attestHop({
    chain,
    signer: mockSigner('did:key:entropy-witness'),
    pidId: 'pid:entropy-witness',
    attestedAtPLo: 1001,
    attestedPhase: 'rising',
    incomingPayloadHash: 'h0',
    note: 'agent-axis-entropy',
    context: ctx,
  });
  chain = await attestHop({
    chain,
    signer: mockSigner('did:key:metacog-witness'),
    pidId: 'pid:metacog-witness',
    attestedAtPLo: 1002,
    attestedPhase: 'rising',
    incomingPayloadHash: 'h0',
    note: 'metacog-revisit-rate',
    context: ctx,
  });
  chain = await attestHop({
    chain,
    signer: mockSigner('did:key:cadence-witness'),
    pidId: 'pid:cadence-witness',
    attestedAtPLo: 1003,
    attestedPhase: 'peak',
    incomingPayloadHash: 'h0',
    note: 'biological-cadence',
    context: ctx,
  });
  return chain;
}

function humanResult(overrides: Partial<HumanDetectionResult> = {}): HumanDetectionResult {
  return {
    pid: 'pid:subject',
    isHuman: 1,
    confidence: 0.97,
    signals: {
      agentAxisEntropy: 0.82,
      metacogRevisitRate: 0.41,
      crossAxisCorrelation: 0.68,
      biologicalCadence: 0.91,
      bruteForceResistance: 0.77,
      observationCount: 240,
      observedForMs: 12_000,
    },
    atEpochMs: 1_000_500,
    ...overrides,
  };
}

// ─── canonicalHumanAttestationBytes ─────────────────────────────────

describe('canonicalHumanAttestationBytes', () => {
  it('is deterministic', async () => {
    const chain = await buildMultiSignalChain();
    const issuer = mockSigner('did:key:issuer');
    const cert = await issueHumanAttestation({
      detectionResult: humanResult(),
      chain,
      issuer,
      context: ctx,
    });
    const a = canonicalHumanAttestationBytes(cert);
    const b = canonicalHumanAttestationBytes(cert);
    expect(Array.from(a)).toEqual(Array.from(b));
  });

  it('changes when any bound-defining field changes', async () => {
    const chain = await buildMultiSignalChain();
    const issuer = mockSigner('did:key:issuer');
    const cert = await issueHumanAttestation({
      detectionResult: humanResult(),
      chain,
      issuer,
      context: ctx,
    });
    const baseBytes = canonicalHumanAttestationBytes(cert);

    const mutated = { ...cert, confidence: 0.98 };
    expect(Array.from(canonicalHumanAttestationBytes(mutated))).not.toEqual(
      Array.from(baseBytes)
    );

    const mutated2 = { ...cert, subjectPid: 'pid:other' };
    expect(Array.from(canonicalHumanAttestationBytes(mutated2))).not.toEqual(
      Array.from(baseBytes)
    );

    const mutated3 = { ...cert, calibrationBoundProbability: 0.01 };
    expect(Array.from(canonicalHumanAttestationBytes(mutated3))).not.toEqual(
      Array.from(baseBytes)
    );

    const mutated4 = { ...cert, certificateId: 'different-id' };
    expect(Array.from(canonicalHumanAttestationBytes(mutated4))).not.toEqual(
      Array.from(baseBytes)
    );
  });
});

// ─── canonicalDetectionResultBytes ──────────────────────────────────

describe('canonicalDetectionResultBytes', () => {
  it('is deterministic', () => {
    const r = humanResult();
    expect(Array.from(canonicalDetectionResultBytes(r))).toEqual(
      Array.from(canonicalDetectionResultBytes(r))
    );
  });

  it('changes when any field changes', () => {
    const base = canonicalDetectionResultBytes(humanResult());
    const changedConf = canonicalDetectionResultBytes(humanResult({ confidence: 0.98 }));
    expect(Array.from(base)).not.toEqual(Array.from(changedConf));
    const changedCadence = canonicalDetectionResultBytes(
      humanResult({
        signals: { ...humanResult().signals, biologicalCadence: 0.5 },
      })
    );
    expect(Array.from(base)).not.toEqual(Array.from(changedCadence));
  });
});

// ─── issueHumanAttestation ──────────────────────────────────────────

describe('issueHumanAttestation', () => {
  it('produces a signed certificate for a valid human detection', async () => {
    const chain = await buildMultiSignalChain();
    const issuer = mockSigner('did:key:issuer');
    const cert = await issueHumanAttestation({
      detectionResult: humanResult(),
      chain,
      issuer,
      context: ctx,
    });

    expect(cert.source).toBe('GnosisHumanAttestationCertificate');
    expect(cert.subjectPid).toBe('pid:subject');
    expect(cert.isHuman).toBe(1);
    expect(cert.confidence).toBe(0.97);
    expect(cert.calibrationBoundProbability).toBe(DEFAULT_CALIBRATION_BOUND);
    expect(cert.issuerDid).toBe('did:key:issuer');
    expect(cert.detectionResultHash.length).toBeGreaterThan(0);
    expect(cert.issuerSignature.length).toBeGreaterThan(0);
  });

  it('refuses to issue when isHuman = -1 (bot)', async () => {
    const chain = await buildMultiSignalChain();
    const issuer = mockSigner('did:key:issuer');
    await expect(
      issueHumanAttestation({
        detectionResult: humanResult({ isHuman: -1, confidence: 0.99 }),
        chain,
        issuer,
        context: ctx,
      })
    ).rejects.toThrow(/isHuman=-1/);
  });

  it('refuses to issue when isHuman = 0 (undetermined)', async () => {
    const chain = await buildMultiSignalChain();
    const issuer = mockSigner('did:key:issuer');
    await expect(
      issueHumanAttestation({
        detectionResult: humanResult({ isHuman: 0, confidence: 0.99 }),
        chain,
        issuer,
        context: ctx,
      })
    ).rejects.toThrow(/isHuman=0/);
  });

  it('refuses to issue when confidence does not meet the bound', async () => {
    const chain = await buildMultiSignalChain();
    const issuer = mockSigner('did:key:issuer');
    // Default bound 0.05 → requires confidence ≥ 0.95.
    await expect(
      issueHumanAttestation({
        detectionResult: humanResult({ confidence: 0.80 }),
        chain,
        issuer,
        context: ctx,
      })
    ).rejects.toThrow(/does not meet calibration bound/);
  });

  it('refuses to issue when chain is empty', async () => {
    const empty = initAttestationChain({
      chainId: 'c-empty',
      originDid: 'did:key:sensor',
      targetDid: 'did:key:issuer',
      path: mockPath,
      initialPayloadHash: 'h0',
      createdAtPLo: 0,
    });
    const issuer = mockSigner('did:key:issuer');
    await expect(
      issueHumanAttestation({
        detectionResult: humanResult(),
        chain: empty,
        issuer,
        context: ctx,
      })
    ).rejects.toThrow(/zero hops/);
  });

  it('refuses to issue with calibrationBound out of (0, 1)', async () => {
    const chain = await buildMultiSignalChain();
    const issuer = mockSigner('did:key:issuer');
    await expect(
      issueHumanAttestation({
        detectionResult: humanResult(),
        chain,
        issuer,
        context: ctx,
        calibrationBound: 0,
      })
    ).rejects.toThrow(/calibrationBound/);
    await expect(
      issueHumanAttestation({
        detectionResult: humanResult(),
        chain,
        issuer,
        context: ctx,
        calibrationBound: 1,
      })
    ).rejects.toThrow(/calibrationBound/);
    await expect(
      issueHumanAttestation({
        detectionResult: humanResult(),
        chain,
        issuer,
        context: ctx,
        calibrationBound: -0.1,
      })
    ).rejects.toThrow(/calibrationBound/);
  });

  it('honors a custom (stricter) calibration bound', async () => {
    const chain = await buildMultiSignalChain();
    const issuer = mockSigner('did:key:issuer');
    // Stricter bound 0.01 → requires confidence ≥ 0.99.
    const cert = await issueHumanAttestation({
      detectionResult: humanResult({ confidence: 0.995 }),
      chain,
      issuer,
      context: ctx,
      calibrationBound: 0.01,
    });
    expect(cert.calibrationBoundProbability).toBe(0.01);

    // And a result that fits default but NOT the stricter bound is refused.
    await expect(
      issueHumanAttestation({
        detectionResult: humanResult({ confidence: 0.97 }),
        chain,
        issuer,
        context: ctx,
        calibrationBound: 0.01,
      })
    ).rejects.toThrow(/does not meet calibration bound/);
  });
});

// ─── verifyHumanAttestation ─────────────────────────────────────────

describe('verifyHumanAttestation', () => {
  it('accepts a freshly issued valid certificate', async () => {
    const chain = await buildMultiSignalChain();
    const issuer = mockSigner('did:key:issuer');
    const cert = await issueHumanAttestation({
      detectionResult: humanResult(),
      chain,
      issuer,
      context: ctx,
    });

    const result = await verifyHumanAttestation(cert, ctx, mockVerifier);
    expect(result.valid).toBe(true);
    expect(result.chainValid).toBe(true);
    expect(result.issuerSignatureValid).toBe(true);
    expect(result.confidenceMeetsBound).toBe(true);
    expect(result.detectionHashMatches).toBe(true);
    expect(result.reasons.length).toBe(0);
  });

  it('rejects cert with tampered issuer signature', async () => {
    const chain = await buildMultiSignalChain();
    const issuer = mockSigner('did:key:issuer');
    const cert = await issueHumanAttestation({
      detectionResult: humanResult(),
      chain,
      issuer,
      context: ctx,
    });

    const tampered = { ...cert, issuerSignature: new Uint8Array([1, 2, 3, 4]) };
    const result = await verifyHumanAttestation(tampered, ctx, mockVerifier);
    expect(result.valid).toBe(false);
    expect(result.issuerSignatureValid).toBe(false);
  });

  it('rejects cert whose body was silently modified post-signing', async () => {
    const chain = await buildMultiSignalChain();
    const issuer = mockSigner('did:key:issuer');
    const cert = await issueHumanAttestation({
      detectionResult: humanResult(),
      chain,
      issuer,
      context: ctx,
    });
    const mutated = { ...cert, confidence: 0.999 };
    const result = await verifyHumanAttestation(mutated, ctx, mockVerifier);
    expect(result.valid).toBe(false);
    expect(result.issuerSignatureValid).toBe(false);
  });

  it('rejects cert whose detectionResultHash was cleared', async () => {
    const chain = await buildMultiSignalChain();
    const issuer = mockSigner('did:key:issuer');
    const cert = await issueHumanAttestation({
      detectionResult: humanResult(),
      chain,
      issuer,
      context: ctx,
    });
    // Re-sign over the cleared hash so signature passes but hash gate fails.
    const cleared = { ...cert, detectionResultHash: '' };
    const { issuerSignature: _s, ...body } = cleared;
    void _s;
    const canonical = canonicalHumanAttestationBytes(body);
    const sig = await issuer.sign(canonical);
    const reSigned = { ...cleared, issuerSignature: sig };

    const result = await verifyHumanAttestation(reSigned, ctx, mockVerifier);
    expect(result.valid).toBe(false);
    expect(result.detectionHashMatches).toBe(false);
    expect(result.issuerSignatureValid).toBe(true);
  });

  it('rejects cert whose underlying attestation chain is broken', async () => {
    const chain = await buildMultiSignalChain();
    const issuer = mockSigner('did:key:issuer');
    const cert = await issueHumanAttestation({
      detectionResult: humanResult(),
      chain,
      issuer,
      context: ctx,
    });

    const brokenChain: PrismAttestationChain = {
      ...cert.attestationChain,
      hops: [
        { ...cert.attestationChain.hops[0], signature: new Uint8Array([9, 9, 9]) },
        ...cert.attestationChain.hops.slice(1),
      ],
    };
    const brokenCert = { ...cert, attestationChain: brokenChain };

    const result = await verifyHumanAttestation(brokenCert, ctx, mockVerifier);
    expect(result.valid).toBe(false);
    expect(result.chainValid).toBe(false);
  });

  it('rejects cert whose confidence is below its own bound (re-signed)', async () => {
    const chain = await buildMultiSignalChain();
    const issuer = mockSigner('did:key:issuer');
    const cert = await issueHumanAttestation({
      detectionResult: humanResult(),
      chain,
      issuer,
      context: ctx,
    });

    // Forge a self-consistent cert claiming a tighter bound than the
    // confidence can defend (simulating a dishonest issuer).
    const forged = { ...cert, calibrationBoundProbability: 0.001 };
    const { issuerSignature: _s, ...body } = forged;
    void _s;
    const canonical = canonicalHumanAttestationBytes(body);
    const sig = await issuer.sign(canonical);
    const forgedSigned = { ...forged, issuerSignature: sig };

    const result = await verifyHumanAttestation(forgedSigned, ctx, mockVerifier);
    expect(result.valid).toBe(false);
    expect(result.confidenceMeetsBound).toBe(false);
    // Signature is self-consistent over the forged body.
    expect(result.issuerSignatureValid).toBe(true);
    expect(result.reasons.some(r => /does not meet calibration bound/.test(r))).toBe(true);
  });

  it('rejects cert whose isHuman is not 1 (even if re-signed)', async () => {
    const chain = await buildMultiSignalChain();
    const issuer = mockSigner('did:key:issuer');
    const cert = await issueHumanAttestation({
      detectionResult: humanResult(),
      chain,
      issuer,
      context: ctx,
    });
    const forged = { ...cert, isHuman: -1 as const };
    const { issuerSignature: _s, ...body } = forged;
    void _s;
    const canonical = canonicalHumanAttestationBytes(body);
    const sig = await issuer.sign(canonical);
    const forgedSigned = { ...forged, issuerSignature: sig };

    const result = await verifyHumanAttestation(forgedSigned, ctx, mockVerifier);
    expect(result.valid).toBe(false);
    expect(result.confidenceMeetsBound).toBe(false);
  });
});

// ─── detectionResultMatchesCertificate ──────────────────────────────

describe('detectionResultMatchesCertificate', () => {
  it('returns true for the original result', async () => {
    const chain = await buildMultiSignalChain();
    const issuer = mockSigner('did:key:issuer');
    const result = humanResult();
    const cert = await issueHumanAttestation({
      detectionResult: result,
      chain,
      issuer,
      context: ctx,
    });
    expect(detectionResultMatchesCertificate(result, cert, ctx)).toBe(true);
  });

  it('returns false when any detection field differs', async () => {
    const chain = await buildMultiSignalChain();
    const issuer = mockSigner('did:key:issuer');
    const result = humanResult();
    const cert = await issueHumanAttestation({
      detectionResult: result,
      chain,
      issuer,
      context: ctx,
    });
    const altered = humanResult({ confidence: 0.98 });
    expect(detectionResultMatchesCertificate(altered, cert, ctx)).toBe(false);
  });

  it('hashDetectionResult yields the same hash as the cert sealed', async () => {
    const chain = await buildMultiSignalChain();
    const issuer = mockSigner('did:key:issuer');
    const result = humanResult();
    const cert = await issueHumanAttestation({
      detectionResult: result,
      chain,
      issuer,
      context: ctx,
    });
    expect(hashDetectionResult(result, ctx)).toBe(cert.detectionResultHash);
  });
});

// ─── JSON Wire Serialization ────────────────────────────────────────

describe('JSON wire serialization', () => {
  it('round-trips through JSON cleanly (with base64 for Uint8Array)', async () => {
    const chain = await buildMultiSignalChain();
    const issuer = mockSigner('did:key:issuer');
    const cert = await issueHumanAttestation({
      detectionResult: humanResult(),
      chain,
      issuer,
      context: ctx,
    });

    // Serialize: convert Uint8Array to base64 strings.
    function toB64(bytes: Uint8Array): string {
      let s = '';
      for (let i = 0; i < bytes.length; i++) s += String.fromCharCode(bytes[i]);
      return typeof btoa === 'function' ? btoa(s) : Buffer.from(s, 'binary').toString('base64');
    }
    function fromB64(b64: string): Uint8Array {
      const bin = typeof atob === 'function' ? atob(b64) : Buffer.from(b64, 'base64').toString('binary');
      const out = new Uint8Array(bin.length);
      for (let i = 0; i < bin.length; i++) out[i] = bin.charCodeAt(i);
      return out;
    }

    const wire = JSON.stringify({
      ...cert,
      issuerSignatureB64: toB64(cert.issuerSignature),
      attestationChain: {
        ...cert.attestationChain,
        hops: cert.attestationChain.hops.map(h => ({
          ...h,
          signatureB64: toB64(h.signature),
        })),
      },
    }, (_k, v) => (v instanceof Uint8Array ? undefined : v));

    const parsed = JSON.parse(wire);
    const rebuilt: HumanAttestationCertificate = {
      ...parsed,
      issuerSignature: fromB64(parsed.issuerSignatureB64),
      attestationChain: {
        ...parsed.attestationChain,
        hops: parsed.attestationChain.hops.map((h: { signatureB64: string; [k: string]: unknown }) => ({
          ...h,
          signature: fromB64(h.signatureB64),
        })),
      },
    };

    const result = await verifyHumanAttestation(rebuilt, ctx, mockVerifier);
    expect(result.valid).toBe(true);
  });
});
